"""Emission compliance tests for intake (auto-generated by pact)."""

from intake.intake import Intake


class TestEmissionCompliance:
    """Verify intake emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test_parse_diff_emits_events(self):
        """Method parse_diff emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = Intake(event_handler=handler)
        try:
            obj.parse_diff()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for parse_diff'
        assert len(completed) >= 1, 'No completed/error event for parse_diff'
        assert invoked[0].get("pact_key") == "PACT:intake:parse_diff"
        assert isinstance(invoked[0].get("input_classification"), list)

