    def test_pact_key_format(self):
        """All emitted events have correctly formatted PACT keys."""
        events, handler = self._make_handler()
        obj = Intake(event_handler=handler)
        try:
            obj.parse_diff()
        except (TypeError, Exception):
            pass
        try:
            obj.classify_hunks()
        except (TypeError, Exception):
            pass
        try:
            obj.run_intake()
        except (TypeError, Exception):
            pass
        try:
            obj.generate_hunk_id()
        except (TypeError, Exception):
            pass
        try:
            obj.generate_request_id()
        except (TypeError, Exception):
            pass
        try:
            obj.detect_language()
        except (TypeError, Exception):
            pass
        for event in events:
            key = event.get("pact_key", "")
            assert key.startswith("PACT:intake:"), f"Bad pact_key: {key}"

